import { RepomixError } from '../shared/errorHandle.js';
export const validateTokenBudget = (totalTokens, tokenBudget) => {
    if (tokenBudget === undefined || totalTokens <= tokenBudget) {
        return;
    }
    throw new RepomixError(`Packed output exceeds the token budget: ${totalTokens.toLocaleString()} > ${tokenBudget.toLocaleString()} tokens. ` +
        'Reduce the output with --compress, narrow the scope with --include/--ignore, or raise --token-budget.');
};
